# app/mailers/send_grid_delivery.rb
class SendGridDelivery
  include SendGrid

  def initialize(options = {})
    @api_key = options[:api_key]
  end

  def deliver!(mail)
    from_email = extract_single_address(mail[:from]) || default_from_address
    to_emails = extract_addresses(mail[:to])
    cc_emails = extract_addresses(mail[:cc])
    bcc_emails = extract_addresses(mail[:bcc])
    reply_to_email = extract_single_address(mail[:reply_to])

    personalization = Personalization.new
    to_emails.each { |email| personalization.add_to(Email.new(email: email)) }
    cc_emails.each { |email| personalization.add_cc(Email.new(email: email)) }
    bcc_emails.each { |email| personalization.add_bcc(Email.new(email: email)) }

    sendgrid_mail = Mail.new
    sendgrid_mail.from = Email.new(email: from_email)
    sendgrid_mail.subject = mail.subject.to_s
    sendgrid_mail.add_personalization(personalization)
    sendgrid_mail.reply_to = Email.new(email: reply_to_email) if reply_to_email.present?

    if mail.multipart?
      mail.parts.each do |part|
        next if attachment_part?(part)

        sendgrid_mail.add_content(Content.new(type: part.mime_type, value: part.body.decoded.to_s))
      end
    else
      mime_type = mail.mime_type.presence || "text/plain"
      sendgrid_mail.add_content(Content.new(type: mime_type, value: mail.body.decoded.to_s))
    end

    add_attachments(sendgrid_mail, mail.attachments)

    response = SendGrid::API.new(api_key: @api_key).client.mail._("send").post(request_body: sendgrid_mail.to_json)

    unless response.status_code.to_i.between?(200, 299)
      raise "SendGrid delivery failed: #{response.status_code} #{response.body}"
    end

    response
  end

  private

  def extract_addresses(field)
    return [] if field.blank?

    Array(field).flat_map do |value|
      Mail::AddressList.new(value.to_s).addresses.map(&:address)
    end.compact.uniq
  end

  def extract_single_address(field)
    extract_addresses(field).first
  end

  def default_from_address
    ActionMailer::Base.default_params[:from] ||
      ENV["DEFAULT_FROM_EMAIL"] ||
      Rails.application.credentials.dig(:sendgrid, :default_from)
  end

  def attachment_part?(part)
    disposition = part.content_disposition.to_s
    disposition.start_with?("attachment") || disposition.start_with?("inline")
  end

  def add_attachments(sendgrid_mail, attachments)
    attachments.each do |attachment|
      sendgrid_mail.add_attachment(
        Attachment.new(
          content: Base64.strict_encode64(attachment.body.decoded),
          type: attachment.mime_type,
          filename: attachment.filename.to_s,
          disposition: attachment.inline? ? "inline" : "attachment",
          content_id: attachment.cid.to_s.presence
        )
      )
    end
  end
end

# app/mailers/application_mailer.rb
class ApplicationMailer < ActionMailer::Base
  default from: (
    ENV["DEFAULT_FROM_EMAIL"] ||
    Rails.application.credentials.dig(:sendgrid, :default_from) ||
    "no-reply@example.com"
  )

  layout "mailer"
end

# app/mailers/user_mailer.rb
class UserMailer < ApplicationMailer
  def welcome_email(user)
    @user = user

    mail(
      to: @user.email,
      subject: "Welcome to #{Rails.application.class.module_parent_name}"
    )
  end
end

